import { RiArrowDownSLine } from 'react-icons/ri';

export function LoadMoreButton(theme: any, onClick: any) {
	return (
		<>
			<button className={`w-screen ${theme.themeBgClassName}`} onClick={onClick}>
				<RiArrowDownSLine />
			</button>
		</>
	);
}
